import java.io.*;
import java.util.Set;
import java.util.logging.Logger;

/**
 * Secure deserialization with class allowlisting using JEP 290
 * Java 9+ Deserialization Filtering
 */
public class SecureDeserializer {

    private static final Logger logger = Logger.getLogger(SecureDeserializer.class.getName());

    // Allowlist of permitted classes for deserialization
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.company.dto.User",
        "com.company.dto.Order",
        "java.lang.String",
        "java.lang.Number",
        "java.util.ArrayList",
        "java.util.HashMap"
    );

    // Blocklist of dangerous classes (gadget chains)
    private static final Set<String> BLOCKED_CLASSES = Set.of(
        "org.apache.commons.collections.functors.InvokerTransformer",
        "org.apache.commons.collections.functors.InstantiateTransformer",
        "org.apache.commons.collections4.functors.InvokerTransformer",
        "org.codehaus.groovy.runtime.ConvertedClosure",
        "org.springframework.beans.factory.ObjectFactory",
        "javax.management.BadAttributeValueExpException"
    );

    public static Object deserializeWithFilter(InputStream inputStream) 
            throws IOException, ClassNotFoundException {

        ObjectInputStream ois = new ObjectInputStream(inputStream) {
            @Override
            protected Class<?> resolveClass(ObjectStreamClass desc)
                    throws IOException, ClassNotFoundException {

                String className = desc.getName();

                // Block dangerous classes immediately
                if (BLOCKED_CLASSES.contains(className)) {
                    logger.severe("SECURITY: Blocked deserialization of dangerous class: " + className);
                    throw new InvalidClassException(
                        "Deserialization of class " + className + " is not allowed"
                    );
                }

                // Enforce allowlist
                if (!isAllowedClass(className)) {
                    logger.warning("SECURITY: Rejected deserialization of non-allowlisted class: " + className);
                    throw new InvalidClassException(
                        "Class " + className + " is not in the allowlist"
                    );
                }

                return super.resolveClass(desc);
            }
        };

        // Set global filter (Java 9+)
        ObjectInputFilter filter = ObjectInputFilter.Config.createFilter(
            "maxarray=1000;maxdepth=5;maxbytes=10000;" +
            "com.company.dto.**;" +
            "java.base/**;" +
            "!*"  // Reject everything else
        );
        ois.setObjectInputFilter(filter);

        return ois.readObject();
    }

    private static boolean isAllowedClass(String className) {
        // Check exact match
        if (ALLOWED_CLASSES.contains(className)) {
            return true;
        }

        // Check package prefixes for DTO classes
        if (className.startsWith("com.company.dto.")) {
            return true;
        }

        // Allow primitive arrays
        if (className.matches("\\[+[ZBCSIJFD]")) {
            return true;
        }

        return false;
    }
}

// Spring Boot Configuration for Global Filter
@Configuration
public class DeserializationSecurityConfig {

    @PostConstruct
    public void configureGlobalDeserializationFilter() {
        // Set JVM-wide deserialization filter (requires -Djdk.serialFilter JVM arg)
        System.setProperty("jdk.serialFilter",
            "maxarray=1000;maxdepth=5;maxbytes=100000;" +
            "com.company.dto.**;" +
            "java.base/**;" +
            "!org.apache.commons.collections.**;" +
            "!org.codehaus.groovy.**;" +
            "!*"
        );
    }
}
